import { useState, useEffect, useRef } from 'react'
import Head from 'next/head'
import { supabase } from '../lib/supabase'

const JCI_LOGO = 'data:image/png;base64,'
const LOGO_50 = 'data:image/png;base64,'
const AEEMCI_LOGO = 'data:image/png;base64,'

export default function Inscription() {
  const [form, setForm] = useState({
    prenom: '', nom: '', genre: '', tel: '', adresse_email: '',
    profil: '', niveau: '', etablissement: ''
  })
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [confirmed, setConfirmed] = useState(null)
  const [qrGenerated, setQrGenerated] = useState(false)

  const showNiveau = form.profil === 'Élève' || form.profil === 'Étudiant(e)'

  useEffect(() => {
    if (confirmed && !qrGenerated) {
      generateQR(confirmed.ref, confirmed.prenom, confirmed.nom, confirmed.tel)
    }
  }, [confirmed])

  async function generateQR(ref, prenom, nom, tel) {
    if (typeof window === 'undefined') return
    try {
      const QRCode = (await import('qrcode')).default
      const qrCanvas = document.getElementById('qr-canvas')
      if (!qrCanvas) return
      await QRCode.toCanvas(qrCanvas, `${ref}|${prenom} ${nom}|${tel}`, {
        width: 160, margin: 1,
        color: { dark: '#1B4332', light: '#FFFFFF' }
      })
      setQrGenerated(true)
    } catch(e) { console.error('QR error:', e) }
  }

  async function downloadQR() {
    if (typeof window === 'undefined') return
    try {
      const QRCode = (await import('qrcode')).default
      const card = document.createElement('canvas')
      card.width = 620
      card.height = 900
      const ctx = card.getContext('2d')

      // Fond crème
      ctx.fillStyle = '#F9F6F0'
      ctx.fillRect(0, 0, 620, 900)

      // Header vert foncé
      ctx.fillStyle = '#1B4332'
      ctx.fillRect(0, 0, 620, 200)

      // Bordure or
      ctx.fillStyle = '#B7791F'
      ctx.fillRect(0, 196, 620, 4)

      // Logo AEEMCI gauche
      const aeemciImg = new Image()
      await new Promise(resolve => {
        aeemciImg.onload = resolve
        aeemciImg.src = AEEMCI_LOGO
      })
      ctx.save()
      ctx.beginPath()
      ctx.arc(56, 80, 44, 0, Math.PI * 2)
      ctx.clip()
      ctx.drawImage(aeemciImg, 12, 36, 88, 88)
      ctx.restore()

      // Logo JCI centre
      const jciImg = new Image()
      await new Promise(resolve => {
        jciImg.onload = resolve
        jciImg.src = JCI_LOGO
      })
      ctx.drawImage(jciImg, 230, 20, 160, 160)

      // Logo 50 ans droite
      const logo50Img = new Image()
      await new Promise(resolve => {
        logo50Img.onload = resolve
        logo50Img.src = LOGO_50
      })
      ctx.drawImage(logo50Img, 490, 50, 110, 63)

      // Titre événement
      ctx.fillStyle = '#fff'
      ctx.font = 'bold 18px sans-serif'
      ctx.textAlign = 'center'
      ctx.fillText('Journée Culturelle Islamique 2026', 310, 190)

      // Séparateur décoratif
      ctx.strokeStyle = '#B7791F'
      ctx.lineWidth = 1.5
      ctx.beginPath()
      ctx.moveTo(80, 220)
      ctx.lineTo(540, 220)
      ctx.stroke()

      // Nom participant
      ctx.fillStyle = '#1B4332'
      ctx.font = 'bold 28px sans-serif'
      ctx.textAlign = 'center'
      ctx.fillText(`${confirmed.prenom} ${confirmed.nom.toUpperCase()}`, 310, 260)

      // Profil
      ctx.fillStyle = '#718096'
      ctx.font = '14px sans-serif'
      ctx.fillText(confirmed.profil + (confirmed.niveau && confirmed.niveau !== '—' ? ' · ' + confirmed.niveau : ''), 310, 285)

      // Ligne or
      ctx.fillStyle = '#B7791F'
      ctx.fillRect(210, 298, 200, 2)

      // BILLET D'ENTREE
      ctx.fillStyle = '#B7791F'
      ctx.font = 'bold 13px sans-serif'
      ctx.fillText("BILLET D'ENTREE", 310, 325)

      // Cadre QR
      const qrSize = 220
      const qrX = (620 - qrSize) / 2
      const qrY = 345

      // Fond blanc arrondi
      ctx.fillStyle = '#fff'
      ctx.strokeStyle = '#B7791F'
      ctx.lineWidth = 2
      ctx.beginPath()
      ctx.roundRect(qrX - 20, qrY - 16, qrSize + 40, qrSize + 32, 14)
      ctx.fill()
      ctx.stroke()

      // Coins décoratifs
      const corners = [[qrX-16, qrY-12], [qrX+qrSize+16, qrY-12], [qrX-16, qrY+qrSize+16], [qrX+qrSize+16, qrY+qrSize+16]]
      ctx.fillStyle = '#1B4332'
      corners.forEach(([cx, cy]) => {
        ctx.beginPath()
        ctx.arc(cx, cy, 5, 0, Math.PI*2)
        ctx.fill()
      })

      // QR Code
      const qrTemp = document.createElement('canvas')
      await QRCode.toCanvas(qrTemp, `${confirmed.ref}|${confirmed.prenom} ${confirmed.nom}|${confirmed.tel}`, {
        width: qrSize, margin: 1,
        color: { dark: '#1B4332', light: '#FFFFFF' }
      })
      ctx.drawImage(qrTemp, qrX, qrY)

      // Référence
      ctx.fillStyle = '#1B4332'
      ctx.font = 'bold 22px monospace'
      ctx.textAlign = 'center'
      ctx.fillText(confirmed.ref, 310, qrY + qrSize + 50)

      // Ligne séparatrice
      ctx.strokeStyle = '#E2E8F0'
      ctx.lineWidth = 1
      ctx.beginPath()
      ctx.moveTo(60, qrY + qrSize + 66)
      ctx.lineTo(560, qrY + qrSize + 66)
      ctx.stroke()

      // Infos pratiques
      ctx.fillStyle = '#4A5568'
      ctx.font = '13px sans-serif'
      ctx.fillText('📅  Samedi 27 juin 2026   ⏰  08h00 – 16h30', 310, qrY + qrSize + 94)
      ctx.fillText('📍  EMPT - Bingerville', 310, qrY + qrSize + 116)

      // Thème
      ctx.fillStyle = '#B7791F'
      ctx.font = 'italic 11px sans-serif'
      ctx.fillText('« Entre coutumes et croyance, retrouver la pureté du Tawhid »', 310, qrY + qrSize + 140)

      // Footer vert
      ctx.fillStyle = '#1B4332'
      ctx.fillRect(0, 855, 620, 45)
      ctx.fillStyle = '#B7791F'
      ctx.fillRect(0, 851, 620, 4)

      ctx.fillStyle = '#F6E05E'
      ctx.font = 'bold 12px sans-serif'
      ctx.textAlign = 'center'
      ctx.fillText('#JCI2026  ·  #AEEMCIBingerville', 310, 873)
      ctx.fillStyle = '#A7C4B5'
      ctx.font = '10px sans-serif'
      ctx.fillText('AEEMCI, pour une identité islamique !', 310, 890)

      const link = document.createElement('a')
      link.download = `Billet-JCI2026-${confirmed.ref}.png`
      link.href = card.toDataURL('image/png')
      link.click()
    } catch(e) { console.error('Download error:', e) }
  }

  function handleChange(e) {
    setForm({ ...form, [e.target.name]: e.target.value })
  }

  async function inscrire() {
    setError('')
    if (!form.prenom || !form.nom || !form.genre || !form.tel || !form.profil) {
      setError('Veuillez remplir tous les champs obligatoires (*).'); return
    }
    setLoading(true)
    const { count } = await supabase.from('participants').select('*', { count: 'exact', head: true })
    const num = ((count || 0) + 1).toString().padStart(4, '0')
    const ref = 'JCI-2026-' + num
    const data = { ref, ...form, statut: 'inscrit', source: 'en ligne' }
    const { error: err } = await supabase.from('participants').insert([data])
    if (err) { setError('Erreur : ' + (err.message || JSON.stringify(err))); setLoading(false); return }
    setConfirmed({ ...data })
    setLoading(false)
  }

  function reset() {
    setForm({ prenom: '', nom: '', genre: '', tel: '', adresse_email: '', profil: '', niveau: '', etablissement: '' })
    setConfirmed(null)
    setQrGenerated(false)
  }

  return (
    <>
      <Head>
        <title>Inscription JCI 2026 — AEEMCI Bingerville</title>
        <meta name="description" content="Inscrivez-vous à la Journée Culturelle Islamique 2026" />
        <link rel="stylesheet" href="https://cdn.jsdelivr.net/npm/@tabler/icons-webfont@latest/tabler-icons.min.css" />
      </Head>

      <style>{`
        body { background: #F7F5F0; }
        .ins-page { min-height: 100vh; background: linear-gradient(160deg, #F7F5F0 0%, #EDF7F1 100%); }

        /* HEADER */
        .ins-hdr { background: #1B4332; border-bottom: 4px solid #B7791F; }
        .ins-hdr-inner { max-width: 700px; margin: 0 auto; padding: 12px 16px; display: flex; align-items: center; justify-content: space-between; gap: 12px; flex-wrap: wrap; }
        .ins-hdr-logos { display: flex; align-items: center; gap: 10px; }
        .ins-hdr-logos img { height: 48px; width: auto; border-radius: 50%; background: white; padding: 2px; }
        .ins-hdr-logos img.logo-50 { border-radius: 4px; background: white; padding: 4px; height: 36px; }
        .ins-hdr-text h1 { font-size: 14px; font-weight: 700; color: #fff; line-height: 1.2; }
        .ins-hdr-text p { font-size: 10px; color: #A7C4B5; margin-top: 1px; }

        /* BANNER */
        .ins-banner { background: linear-gradient(135deg, #1B4332 0%, #2D5A45 100%); border: 2px solid #B7791F; border-radius: 16px; padding: 20px; margin-bottom: 20px; position: relative; overflow: hidden; }
        .ins-banner::before { content: ''; position: absolute; top: -30px; right: -30px; width: 120px; height: 120px; border-radius: 50%; background: rgba(183,121,31,.15); }
        .ins-banner-logos { display: flex; align-items: center; justify-content: center; gap: 16px; margin-bottom: 14px; }
        .ins-banner-logos img { height: 64px; width: auto; filter: drop-shadow(0 2px 4px rgba(0,0,0,.3)); }
        .ins-banner-logos img.logo-50 { height: 44px; background: white; border-radius: 6px; padding: 4px; }
        .ins-banner-logos img.aeemci { height: 60px; border-radius: 50%; background: white; padding: 4px; }
        .ins-banner-eye { font-size: 11px; color: #F6E05E; font-weight: 600; letter-spacing: .5px; margin-bottom: 6px; text-align: center; }
        .ins-banner-title { font-size: 22px; font-weight: 700; color: #fff; margin-bottom: 8px; text-align: center; line-height: 1.2; }
        .ins-banner-theme { font-size: 12px; color: #D4E6DC; font-style: italic; padding: 8px 12px; background: rgba(255,255,255,.08); border-left: 3px solid #F6E05E; border-radius: 0 8px 8px 0; margin-bottom: 12px; }
        .ins-banner-pills { display: flex; flex-wrap: wrap; gap: 6px; justify-content: center; }
        .ins-pill { background: rgba(255,255,255,.12); color: #E2E8F0; font-size: 11px; padding: 4px 12px; border-radius: 20px; display: flex; align-items: center; gap: 4px; border: 0.5px solid rgba(255,255,255,.2); }

        /* MAIN */
        .ins-main { padding: 20px 16px; max-width: 700px; margin: 0 auto; }

        /* CARD */
        .ins-card { background: #fff; border: 1px solid #E2E8F0; border-radius: 16px; padding: 20px; margin-bottom: 14px; box-shadow: 0 2px 12px rgba(27,67,50,.06); }
        .ins-card-hd { font-size: 13px; font-weight: 600; color: #1B4332; display: flex; align-items: center; gap: 8px; margin-bottom: 14px; padding-bottom: 10px; border-bottom: 2px solid #F0FFF4; }
        .ins-card-hd i { font-size: 16px; color: #B7791F; }

        /* FORM */
        .ins-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
        .ins-span2 { grid-column: 1 / -1; }
        .ins-fg { display: flex; flex-direction: column; gap: 4px; margin-bottom: 10px; }
        .ins-fg label { font-size: 11px; font-weight: 600; color: #4A5568; text-transform: uppercase; letter-spacing: .3px; }
        .ins-fg input, .ins-fg select { padding: 10px 12px; border: 1.5px solid #E2E8F0; border-radius: 10px; font-size: 13px; background: #F9FAFB; color: #1A202C; outline: none; width: 100%; transition: all .15s; }
        .ins-fg input:focus, .ins-fg select:focus { border-color: #1B4332; background: #fff; box-shadow: 0 0 0 3px rgba(27,67,50,.08); }
        .ins-fg input::placeholder { color: #A0AEC0; }
        .ins-dv { border: none; border-top: 1.5px solid #F0FFF4; margin: 14px 0; }

        /* BTN */
        .ins-btn { display: inline-flex; align-items: center; justify-content: center; gap: 7px; padding: 11px 20px; border-radius: 10px; border: none; font-size: 14px; font-weight: 600; cursor: pointer; transition: all .15s; white-space: nowrap; }
        .ins-btn-green { background: linear-gradient(135deg, #1B4332, #2D5A45); color: #fff; box-shadow: 0 2px 8px rgba(27,67,50,.25); }
        .ins-btn-green:hover { transform: translateY(-1px); box-shadow: 0 4px 12px rgba(27,67,50,.35); }
        .ins-btn-green:disabled { background: #9AE6B4; box-shadow: none; cursor: not-allowed; transform: none; }
        .ins-btn-gold { background: linear-gradient(135deg, #B7791F, #C89232); color: #fff; box-shadow: 0 2px 8px rgba(183,121,31,.3); }
        .ins-btn-gold:hover { transform: translateY(-1px); box-shadow: 0 4px 12px rgba(183,121,31,.4); }
        .ins-btn-full { width: 100%; }
        .ins-btn-sm { padding: 8px 16px; font-size: 13px; }

        /* ALERT */
        .ins-alert { padding: 10px 14px; border-radius: 10px; font-size: 12px; margin-bottom: 14px; display: flex; align-items: flex-start; gap: 8px; }
        .ins-al-err { background: #FFF5F5; color: #742A2A; border: 1px solid #FC8181; }

        /* CONFIRM */
        .ins-conf { text-align: center; padding: 10px 0 16px; }
        .ins-chk { width: 60px; height: 60px; border-radius: 50%; background: linear-gradient(135deg, #C6F6D5, #9AE6B4); display: flex; align-items: center; justify-content: center; margin: 0 auto 14px; color: #1B4332; font-size: 30px; box-shadow: 0 4px 12px rgba(27,67,50,.2); }
        .ins-qr-box { background: linear-gradient(135deg, #FFFBEB, #FEF3C7); border: 2px solid #B7791F; border-radius: 16px; padding: 20px 16px; margin: 14px auto; max-width: 220px; display: flex; flex-direction: column; align-items: center; box-shadow: 0 4px 16px rgba(183,121,31,.15); }
        .ins-btn-group { display: flex; gap: 10px; justify-content: center; flex-wrap: wrap; margin-top: 16px; }

        @media (max-width: 480px) {
          .ins-grid { grid-template-columns: 1fr; }
          .ins-span2 { grid-column: 1; }
          .ins-banner-logos img { height: 48px; }
          .ins-banner-logos img.aeemci { height: 48px; }
          .ins-banner-logos img.logo-50 { height: 34px; }
        }
      `}</style>

      <div className="ins-page">
        <div className="ins-hdr">
          <div className="ins-hdr-inner">
            <div className="ins-hdr-logos">
              <img src={AEEMCI_LOGO} alt="AEEMCI" />
              <img src={JCI_LOGO} alt="JCI Logo" />
              <img src={LOGO_50} alt="50 ans AEEMCI" className="logo-50" />
            </div>
            <div className="ins-hdr-text">
              <h1>Inscription JCI 2026</h1>
              <p>AEEMCI · Sous-comité de Bingerville</p>
            </div>
          </div>
        </div>

        <div className="ins-main">
          <div className="ins-banner">
            <div className="ins-banner-logos">
              <img src={AEEMCI_LOGO} alt="AEEMCI" className="aeemci" />
              <img src={JCI_LOGO} alt="JCI" />
              <img src={LOGO_50} alt="50 ans" className="logo-50" />
            </div>
            <div className="ins-banner-eye">AEEMCI · Journée Culturelle Islamique · 50e anniversaire</div>
            <div className="ins-banner-title">Journée Culturelle Islamique 2026</div>
            <div className="ins-banner-theme">« Entre coutumes et croyance, retrouver la pureté du Tawhid »</div>
            <div className="ins-banner-pills">
              <span className="ins-pill"><i className="ti ti-calendar" /> Samedi 27 juin 2026</span>
              <span className="ins-pill"><i className="ti ti-clock" /> 08h00 – 16h30</span>
              <span className="ins-pill"><i className="ti ti-map-pin" /> EMPT - Bingerville</span>
              <span className="ins-pill"><i className="ti ti-ticket" /> Entrée libre sur inscription</span>
            </div>
          </div>

          {error && <div className="ins-alert ins-al-err"><i className="ti ti-alert-circle" />{error}</div>}

          {!confirmed ? (
            <div className="ins-card">
              <div className="ins-card-hd"><i className="ti ti-user-circle" />Informations personnelles</div>
              <div className="ins-grid">
                <div className="ins-fg"><label>Prénom *</label><input name="prenom" value={form.prenom} onChange={handleChange} placeholder="ex. Fatima" /></div>
                <div className="ins-fg"><label>Nom *</label><input name="nom" value={form.nom} onChange={handleChange} placeholder="ex. KONÉ" /></div>
                <div className="ins-fg"><label>Genre *</label>
                  <select name="genre" value={form.genre} onChange={handleChange}>
                    <option value="">— Choisir —</option>
                    <option>Masculin</option><option>Féminin</option>
                  </select>
                </div>
                <div className="ins-fg"><label>Téléphone *</label><input name="tel" value={form.tel} onChange={handleChange} placeholder="07 XX XX XX XX" /></div>
                <div className="ins-fg ins-span2"><label>Email</label><input name="adresse_email" type="email" value={form.adresse_email} onChange={handleChange} placeholder="votre@email.com" /></div>
              </div>
              <hr className="ins-dv" />
              <div className="ins-card-hd"><i className="ti ti-school" />Profil scolaire / académique</div>
              <div className="ins-grid">
                <div className="ins-fg"><label>Profil *</label>
                  <select name="profil" value={form.profil} onChange={handleChange}>
                    <option value="">— Choisir —</option>
                    <option>Élève</option><option>Étudiant(e)</option><option>Enseignant(e)</option>
                    <option>Membre de la communauté</option><option>Autre</option>
                  </select>
                </div>
                {showNiveau && (
                  <div className="ins-fg"><label>Classe / Niveau *</label>
                    <select name="niveau" value={form.niveau} onChange={handleChange}>
                      <option value="">— Choisir —</option>
                      <optgroup label="Secondaire"><option>6e</option><option>5e</option><option>4e</option><option>3e</option><option>2nde</option><option>1ère</option><option>Terminale</option></optgroup>
                      <optgroup label="Supérieur"><option>Licence 1</option><option>Licence 2</option><option>Licence 3</option><option>Master 1</option><option>Master 2</option><option>Doctorat</option><option>BTS / DUT</option></optgroup>
                      <optgroup label="Autre"><option>Non applicable</option></optgroup>
                    </select>
                  </div>
                )}
                <div className="ins-fg ins-span2"><label>Établissement / Institution</label>
                  <input name="etablissement" value={form.etablissement} onChange={handleChange} placeholder="ex. EMPT Bingerville, Université FHB…" />
                </div>
              </div>
              <hr className="ins-dv" />
              <button className="ins-btn ins-btn-green ins-btn-full" onClick={inscrire} disabled={loading}>
                {loading ? <><i className="ti ti-loader" /> Inscription en cours…</> : <><i className="ti ti-send" /> S&apos;inscrire à la JCI 2026</>}
              </button>
            </div>
          ) : (
            <div className="ins-card">
              <div className="ins-conf">
                <div className="ins-chk"><i className="ti ti-check" /></div>
                <div style={{ fontSize: 19, fontWeight: 700, color: '#1B4332', marginBottom: 4 }}>
                  Bienvenue, {confirmed.prenom} {confirmed.nom.toUpperCase()} !
                </div>
                <div style={{ fontSize: 13, color: '#718096', marginBottom: 16 }}>
                  Votre inscription à la JCI 2026 est confirmée.
                </div>
                <div className="ins-qr-box">
                  <div style={{ fontSize: 11, color: '#744210', fontWeight: 700, marginBottom: 10, letterSpacing: 1 }}>VOTRE QR CODE</div>
                  <div style={{ background: '#fff', borderRadius: 10, padding: 8, display: 'inline-flex', boxShadow: '0 2px 8px rgba(0,0,0,.1)' }}>
                    <canvas id="qr-canvas" style={{ display: 'block' }}></canvas>
                  </div>
                  <div style={{ fontSize: 15, fontWeight: 700, color: '#1B4332', marginTop: 10, letterSpacing: 2, fontFamily: 'monospace' }}>{confirmed.ref}</div>
                  <div style={{ fontSize: 10, color: '#718096', marginTop: 4 }}>Présentez ce code le 27 juin 2026</div>
                  <div style={{ fontSize: 10, color: '#B7791F', marginTop: 2, fontWeight: 500 }}>📍 EMPT - Bingerville · 08h00</div>
                </div>
                <div className="ins-btn-group">
                  <button className="ins-btn ins-btn-gold ins-btn-sm" onClick={downloadQR}>
                    <i className="ti ti-download" /> Télécharger le billet
                  </button>
                  <button className="ins-btn ins-btn-green ins-btn-sm" onClick={reset}>
                    <i className="ti ti-user-plus" /> Nouvelle inscription
                  </button>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </>
  )
}
